#include <iostream>
#include <unordered_map>
#include <chrono>
#include <memory>

struct Session {
    std::string data;
    std::chrono::system_clock::time_point expiryTime;
};

class Cache {
private:
    std::unordered_map<std::string, std::shared_ptr<Session>> sessions;

public:
    void createSession(const std::string& sessionId, const std::string& sessionData, int expirySeconds) {
        auto expiry = std::chrono::system_clock::now() + std::chrono::seconds(expirySeconds);
        sessions[sessionId] = std::make_shared<Session>({sessionData, expiry});
    }

    std::string accessSession(const std::string& sessionId) {
        auto it = sessions.find(sessionId);
        if (it != sessions.end()) {
            if (std::chrono::system_clock::now() < it->second->expiryTime) {
                return it->second->data;
            } else {
                // Session expired, free memory but keep the session ID
                sessions.erase(it);
            }
        }
        return ""; // Return empty string if session does not exist or has expired
    }

    void invalidateSession(const std::string& sessionId) {
        auto it = sessions.find(sessionId);
        if (it != sessions.end()) {
            sessions.erase(it);
        }
    }
};

